7626	\begin{lemma}
7627	
7628	\leanok
7629	[One-sided binary distributivity in the slice]
7630	  \label{lem:prod_coproduct_distrib}
7631	  \lean{CategoryTheory.FinitaryPreExtensive.prod_coproduct_distrib}
7632	  \uses{lem:isIso_sigmaDesc_map_mathlib, lem:isIso_sigmaDesc_fst_mathlib}
7633	  Let \(\mathcal{C}\) be a finitary pre-extensive category with pullbacks, \(S \in \mathcal{C}\), and
7634	  fix objects over \(S\). For a finite family \((Y_\tau \to S)_\tau\) and a single \(A \to S\) the
7635	  fibre product distributes over the coproduct on each side:
7636	  \[
7637	    A \times_S \bigl(\textstyle\coprod_{\tau} Y_\tau\bigr)
7638	      \;\cong\;
7639	    \coprod_{\tau} \bigl(A \times_S Y_\tau\bigr),
7640	    \qquad
7641	    \bigl(\textstyle\coprod_{i} X_i\bigr) \times_S B
7642	      \;\cong\;
7643	    \coprod_{i} \bigl(X_i \times_S B\bigr),
7644	  \]
7645	  with each isomorphism the \(\operatorname{Sigma.desc}\) of the pullback maps, hence compatible with
7646	  the projections to \(S\).
7647	\end{lemma}
7648	\begin{proof}
7649	  \uses{lem:isIso_sigmaDesc_map_mathlib, lem:isIso_sigmaDesc_fst_mathlib}
7650	  This is the binary distributivity instance Lemma~\ref{lem:isIso_sigmaDesc_map_mathlib}
7651	  (\(\coprod_{(i,j)}(X_i \times_S Y_j) \cong (\coprod_i X_i)\times_S(\coprod_j Y_j)\)) specialised by
7652	  taking one of the two families to be a singleton: with the first family the singleton \(\{A\}\)
7653	  one gets \(A \times_S \coprod_\tau Y_\tau \cong \coprod_\tau (A \times_S Y_\tau)\), and with the
7654	  second family the singleton \(\{B\}\) one gets \((\coprod_i X_i)\times_S B \cong \coprod_i (X_i
7655	  \times_S B)\).
7656	\end{proof}
