7658	\begin{lemma}[One-sided distributivity in \(\operatorname{Over} S\) binary-product form]
7659	  \label{lem:overProd_coproduct_distrib}
7660	  \lean{CategoryTheory.FinitaryPreExtensive.overProd_coproduct_distrib}
7661	  % NOTE: build target. The Lean declaration does not exist yet; the name is the prover's target.
7662	  \uses{lem:prod_coproduct_distrib, lem:overProdLeftIsoPullback_mathlib}
7663	  Let \(\mathcal{C}\) be a finitary pre-extensive category with pullbacks and \(S \in \mathcal{C}\).
7664	  For a finite index type \(\iota : \operatorname{Type} 0\), a family \((A_i)_{i \in \iota}\) of
7665	  objects of \(\operatorname{Over} S\), and a single \(B \in \operatorname{Over} S\), the
7666	  \emph{binary product in the slice} distributes over the coproduct:
7667	  \[
7668	    \bigl(\textstyle\coprod_{i} A_i\bigr) \times B
7669	      \;\cong\;
7670	    \coprod_{i} \bigl(A_i \times B\bigr)
7671	      \qquad\text{in } \operatorname{Over} S,
7672	  \]
7673	  where \(\times\) is the categorical binary product of \(\operatorname{Over} S\). This is the form in
7674	  which the inductive step of Lemma~\ref{lem:coproduct_distrib_fibrePower} consumes distributivity:
7675	  the recursion lives entirely in \(\operatorname{Over} S\), so it needs the slice binary product, not
7676	  the \(\mathcal{C}\)-level fibre product of Lemma~\ref{lem:prod_coproduct_distrib}.
7677	\end{lemma}
7678	\begin{proof}
7679	  \uses{lem:prod_coproduct_distrib, lem:overProdLeftIsoPullback_mathlib}
7680	  The forgetful functor \(\operatorname{Over} S \to \mathcal{C}\) reflects isomorphisms: a morphism of
7681	  the slice is an isomorphism iff its underlying \(\mathcal{C}\)-morphism (its \(.\mathrm{left}\)) is.
7682	  It therefore suffices to identify the underlying objects. The coproduct in \(\operatorname{Over} S\)
7683	  is computed on underlying objects, \((\coprod_i A_i).\mathrm{left} = \coprod_i A_i.\mathrm{left}\),
7684	  and the underlying object of a binary product in \(\operatorname{Over} S\) is the fibre product of
7685	  the two structure maps, \((Y \times Z).\mathrm{left} \cong \operatorname{pullback} Y.\mathrm{hom}\,
7686	  Z.\mathrm{hom}\), via \(\operatorname{Over.prodLeftIsoPullback}\)
7687	  (Lemma~\ref{lem:overProdLeftIsoPullback_mathlib}). Under these identifications both sides become
7688	  the \(\mathcal{C}\)-level objects of the one-sided distributivity
7689	  Lemma~\ref{lem:prod_coproduct_distrib}: \((\coprod_i A_i.\mathrm{left}) \times_S B.\mathrm{left}\)
7690	  on the left and \(\coprod_i (A_i.\mathrm{left} \times_S B.\mathrm{left})\) on the right. Matching
7691	  \(.\mathrm{left}\) with that \(\mathcal{C}\)-level isomorphism, and noting all comparison maps commute
7692	  with the projection to \(S\), gives the slice isomorphism.
7693	\end{proof}
