7695	\begin{lemma}[The underlying object of a slice binary product is the pullback]
7696	  \label{lem:overProdLeftIsoPullback_mathlib}
7697	  \lean{CategoryTheory.Over.prodLeftIsoPullback}
7698	  \mathlibok
7699	  \textit{Provided by Mathlib.}
7700	  For \(S \in \mathcal{C}\) and two objects \(Y, Z \in \operatorname{Over} S\) (with \(\mathcal{C}\)
7701	  having the relevant pullback), the underlying object of their binary product in the slice is the
7702	  fibre product of their structure maps: \((Y \times Z).\mathrm{left} \cong \operatorname{pullback}
7703	  Y.\mathrm{hom}\, Z.\mathrm{hom}\), compatibly with the projections.
7704	\end{lemma}
