7706	\begin{lemma}
7707	
7708	\leanok
7709	[Nested coproduct flattens and reindexes to the next fibre power]
7710	  \label{lem:coproduct_fibrePower_reindex}
7711	  \lean{CategoryTheory.FinitaryPreExtensive.coproduct_fibrePower_reindex}
7712	  \uses{lem:sigmaSigmaIso_mathlib}
7713	  Let \(\iota\) be a finite index type, \(S \in \mathcal{C}\), \((X_i \to S)_i\) a family over
7714	  \(S\), and for \(\tau : \mathrm{Fin}(p+1)\to\iota\) write \(Y_\tau = X_{\tau(0)} \times_S \cdots
7715	  \times_S X_{\tau(p)}\). Then the nested coproduct flattens and reindexes to a coproduct over
7716	  \((p+2)\)-fold multi-indices:
7717	  \[
7718	    \coprod_{i}\coprod_{\tau} \bigl(X_i \times_S Y_\tau\bigr)
7719	      \;\cong\;
7720	    \coprod_{(i,\tau)} \bigl(X_i \times_S Y_\tau\bigr)
7721	      \;\cong\;
7722	    \coprod_{\sigma : \mathrm{Fin}(p+2) \to \iota}
7723	      \bigl(X_{\sigma(0)} \times_S \cdots \times_S X_{\sigma(p+1)}\bigr),
7724	  \]
7725	  where the second isomorphism is the reindexing \((i, \tau) \mapsto \sigma =
7726	  \operatorname{Fin.cons} i\,\tau\), a bijection \(\iota \times (\mathrm{Fin}(p+1)\to\iota) \cong
7727	  (\mathrm{Fin}(p+2)\to\iota)\), under which \(X_i \times_S Y_\tau\) is exactly the \((p+2)\)-fold
7728	  fibre power \(X_{\sigma(0)} \times_S \cdots \times_S X_{\sigma(p+1)}\).
7729	\end{lemma}
7730	\begin{proof}
7731	  \uses{lem:sigmaSigmaIso_mathlib}
7732	  The first isomorphism is \(\operatorname{sigmaSigmaIso}\) of
7733	  Lemma~\ref{lem:sigmaSigmaIso_mathlib}, collapsing the doubly-indexed coproduct
7734	  \(\coprod_i \coprod_\tau\) into a coproduct over pairs \((i,\tau)\). The
7735	  \(\operatorname{Fin.cons}\) bijection \(\iota \times (\mathrm{Fin}(p+1)\to\iota) \cong
7736	  (\mathrm{Fin}(p+2)\to\iota)\), \((i,\tau)\mapsto \operatorname{Fin.cons} i\,\tau\), reindexes that
7737	  coproduct over \(\sigma\); and since \(\sigma(0) = i\) and \(\sigma(k+1) = \tau(k)\), the component
7738	  \(X_i \times_S Y_\tau = X_i \times_S (X_{\tau(0)} \times_S \cdots)\) is term-for-term the
7739	  \((p+2)\)-fold fibre power \(X_{\sigma(0)} \times_S \cdots \times_S X_{\sigma(p+1)}\).
7740	\end{proof}
